import { auth } from "@/lib/auth";
import { redirect } from "next/navigation";
import { PageHeader } from "@/components/layout/PageHeader";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import {
  faUsers,
  faCalendarDays,
  faListOl,
  faBolt,
  faTrophy,
} from "@fortawesome/free-solid-svg-icons";
import Link from "next/link";

export const metadata = { title: "Dashboard" };

export default async function DashboardPage() {
  const session = await auth();
  if (!session) redirect("/login");

  return (
    <div>
      <PageHeader
        eyebrow="Welcome back, Coach"
        title={session.user?.name ?? "Dashboard"}
        subtitle="Here's a quick look at your team"
      />

      {/* Stat cards */}
      <div className="mb-6 grid grid-cols-2 gap-4 md:grid-cols-4">
        {[
          { label: "Roster",   value: "—", icon: faUsers,       href: "/roster",   color: "var(--color-text-brand)" },
          { label: "Games",    value: "—", icon: faCalendarDays, href: "/schedule", color: "#5b8fff" },
          { label: "Lineup",   value: "—", icon: faListOl,      href: "/lineup",   color: "#c084fc" },
          { label: "Season W/L", value: "—", icon: faTrophy,    href: "/schedule", color: "var(--color-text-brand)" },
        ].map((card) => (
          <Link
            key={card.label}
            href={card.href}
            className="card flex flex-col gap-3 transition-colors hover:border-[var(--color-border-default)]"
            style={{ textDecoration: "none" }}
          >
            <div className="flex items-center justify-between">
              <span
                className="text-xs font-bold uppercase tracking-widest"
                style={{ color: "var(--color-text-muted)", fontFamily: "var(--font-body)" }}
              >
                {card.label}
              </span>
              <FontAwesomeIcon
                icon={card.icon}
                style={{ width: 14, height: 14, color: card.color }}
              />
            </div>
            <span
              style={{
                fontFamily: "var(--font-display)",
                fontSize: "2.5rem",
                fontWeight: 900,
                color: card.color,
                lineHeight: 1,
              }}
            >
              {card.value}
            </span>
          </Link>
        ))}
      </div>

      {/* Go Live CTA */}
      <div
        className="card card-brand flex flex-col items-center gap-4 py-10 text-center md:flex-row md:justify-between md:text-left"
      >
        <div>
          <div className="eyebrow mb-2">Game Day</div>
          <h2
            style={{
              fontFamily: "var(--font-display)",
              fontSize: "1.75rem",
              fontWeight: 800,
              color: "var(--color-text-primary)",
              margin: 0,
            }}
          >
            Ready to start a game?
          </h2>
          <p className="mt-1 text-sm" style={{ color: "var(--color-text-muted)" }}>
            Head to the Schedule tab and hit GO LIVE on today's game.
          </p>
        </div>
        <Link
          href="/schedule"
          className="flex shrink-0 items-center gap-2 rounded-lg px-6 py-3 font-bold transition-opacity hover:opacity-80"
          style={{
            background: "var(--color-text-brand)",
            color: "#000",
            fontFamily: "var(--font-display)",
            fontSize: "1rem",
            letterSpacing: "0.05em",
            textDecoration: "none",
          }}
        >
          <FontAwesomeIcon icon={faBolt} style={{ width: 14, height: 14 }} />
          VIEW SCHEDULE
        </Link>
      </div>
    </div>
  );
}
